WHERE c.deleted=0

    AND (c.class_code LIKE CONCAT('%', #{query.keyword}, '%') OR c.class_name LIKE CONCAT('%', #{query.keyword}, '%') OR m.major_name LIKE CONCAT('%', #{query.keyword}, '%') OR g.grade_name LIKE CONCAT('%', #{query.keyword}, '%'))

AND c.major_id = #{query.majorId}
AND c.grade_id = #{query.gradeId}
AND c.status = #{query.status}
